+ * OF THIS SOFTWARE, EVEN IF ADVISED OF THE POSSIBILITY OF SUCH DAMAGE.
+ */
+
+#include "nvcomp/bitcomp.hpp"
+#include "benchmark_hlif.hpp"
+
+#include <string.h>
+
+using namespace nvcomp;
+
+static void print_usage()
+{
+  printf("Usage: benchmark_bitcomp [OPTIONS]\n");
+  printf("  %-35s Binary dataset filename (required).\n", "-f, --filename");
+  printf("  %-35s GPU device number (default 0)\n", "-g, --gpu");
+  printf("  %-35s Data type (default 'char', options are 'char', 'short', 'int', 'int64')\n", "-t, --type");
+  printf(
+      "  %-35s Output GPU memory allocation sizes (default off)\n",
+      "-m --memory");
+  exit(1);
+}
+
+
+int main(int argc, char* argv[])
+{
+  char* fname = NULL;
+  int gpu_num = 0;
+  int verbose_memory = 0;
+  nvcompType_t data_type = NVCOMP_TYPE_CHAR;
+
+  // Parse command-line arguments
+  char** argv_end = argv + argc;
+  argv += 1;
+  while (argv != argv_end) {
+    char* arg = *argv++;
+    if (strcmp(arg, "--help") == 0 || strcmp(arg, "-?") == 0) {
+      print_usage();
+      return 1;
+    }
+    if (strcmp(arg, "--memory") == 0 || strcmp(arg, "-m") == 0) {
+      verbose_memory = 1;
+      continue;
+    }
+
+    // all arguments below require at least a second value in argv
+    if (argv >= argv_end) {
+      print_usage();
+      return 1;
+    }
+
+    char* optarg = *argv++;
+    if (strcmp(arg, "--filename") == 0 || strcmp(arg, "-f") == 0) {
+      fname = optarg;
+      continue;
+    }
+    if (strcmp(arg, "--gpu") == 0 || strcmp(arg, "-g") == 0) {
+      gpu_num = atoi(optarg);
+      continue;
+    }
+    if (strcmp(arg, "--type") == 0 || strcmp(arg, "-t") == 0) {
+      if (strcmp(optarg, "char") == 0) {
+        data_type = NVCOMP_TYPE_CHAR;
+      } else if (strcmp(optarg, "short") == 0) {
+        data_type = NVCOMP_TYPE_SHORT;
+      } else if (strcmp(optarg, "int") == 0) {
+        data_type = NVCOMP_TYPE_INT;
+      } else if (strcmp(optarg, "int64") == 0) {
+        data_type = NVCOMP_TYPE_LONGLONG;
+      } else {
+        print_usage();
+        return 1;
+      }
+      continue;
+    }
+
+    print_usage();
+    return 1;
+  }
+
+  if (fname == NULL) {
+    print_usage();
+    return 1;
+  }
+
+  cudaSetDevice(gpu_num);
+
+  cudaStream_t stream;
+  cudaStreamCreate(&stream);
+
+  BitcompManager comp_manager{data_type, 0, stream};
+
+  run_benchmark_from_file(fname, comp_manager, verbose_memory, stream);
+  CudaUtils::check(cudaStreamDestroy(stream));
+
+  return 0;
+}

