+#pragma once
+
+#include <memory>
+
+#include "nvcomp/lz4.hpp"
+#include "src/Check.h"
+#include "src/CudaUtils.h"
+#include "src/lowlevel/LZ4CompressionKernels.h"
+#include "src/highlevel/LZ4HlifKernels.h"
