+#define CUDA_RT_CALL(call)                                                     \
+  {                                                                            \
+    cudaError_t cudaStatus = call;                                             \
+    if (cudaSuccess != cudaStatus) {                                           \
+      fprintf(                                                                 \
+          stderr,                                                              \
+          "ERROR: CUDA RT call \"%s\" in line %d of file %s failed with %s "   \
