+      1,
+      DEVICE_TO_HOST,
+      stream);
+  CudaUtils::sync(stream);
+
+  if (version == 1) {
+        deserializeAndCopyMetadataFromGPUVersion1(ptr, m_ptr, m_maxSize, stream);
