+      if (flag) {
+        b[0].len = len;
+        b[0].offset = offset;
+
+        {
+          s->q.batch_len[batch] = 1;
+          batch = (batch + 1) & (BATCH_COUNT - 1);
+        }
+      }
+
+      if (bytes_left <= 0) {
+        //printf("bytes_left %d <= 0, exiting\n", bytes_left);
+        flag = false;
+      }
+    }
+
+    if (t == 0) {
+      while (s->q.batch_len[batch] != 0) { NANOSLEEP(100); }
+    }
+  }
+
+  if (!t) {
+    s->q.prefetch_end = 1;
+    s->q.batch_len[batch] = -1;
+    //printf("Marking batch %d with -1\n", batch);
+    s->bytes_left = bytes_left;
+    if (bytes_left != 0)
+      s->error = -2;
