+ * @param out_bytes The required size of the output location in bytes (output).
+ *
+ * @return nvcompSuccess if successful, and an error code otherwise.
+ */
+nvcompError_t nvcompCascadedCompressAutoGetOutputSize(
+    const void* in_ptr,
