+int main(int argc, char* argv[])
+{
+  int gpu_num = 0;
+
+  // Parse command-line arguments
+  while (1) {
+    int option_index = 0;
+    static struct option long_options[]{{"gpu", required_argument, 0, 'g'},
+                                        {"help", no_argument, 0, '?'}};
+    int c;
+    opterr = 0;
+    c = getopt_long(argc, argv, "g?", long_options, &option_index);
+    if (c == -1)
+      break;
+
+    switch (c) {
+    case 'g':
+      gpu_num = atoi(optarg);
+      break;
+    case '?':
+    default:
+      print_usage();
+      exit(1);
+    }
+  }
+
+  cudaSetDevice(gpu_num);
+
+  std::mt19937 rng(0);
+
+  run_tests(rng);
+
+  return 0;
+}
